            self.sessions[session_id]["status"] = "closed"
        else:
            raise ValueError("Session does not exist or is not active")

    def modify_session(self, session_id: str, new_timeout: int) -> None:
        if session_id in self.sessions and self.sessions[session_id]["status"] == "active":
            self.sessions[session_id]["timeout"] = new_timeout
        else:
            raise ValueError("Session does not exist or is not active")

