    private int roomBrightness;

    public SmartHomeSystem() {
        this.roomStatus = STATUS_OFF;
        this.roomBrightness = DEFAULT_BRIGHTNESS;
    }

    public void turnOn(String room) {
        if (room.equals(ROOM_LIVING_ROOM) || room.equals(ROOM_KITCHEN) || room.equals(ROOM_BATHROOM)) {
            this.roomStatus = STATUS_ON;
            this.roomBrightness = DEFAULT_BRIGHTNESS;
        } else {
            throw new IllegalArgumentException("Invalid room: " + room);
        }
    }

    public void turnOff(String room) {
        if (room.equals(ROOM_LIVING_ROOM) || room.equals(ROOM_KITCHEN) || room.equals(ROOM_BATHROOM)) {
            this.roomStatus = STATUS_OFF;
            this.roomBrightness = DEFAULT_BRIGHTNESS;
        } else {
            throw new IllegalArgumentException("Invalid room: " + room);
        }
    }

    public void adjustBrightness(String room, int level) {
        if (room.equals(ROOM_LIVING_ROOM) || room.equals(ROOM_KITCHEN) || room.equals(ROOM_BATHROOM)) {
