using namespace std;

class HardwareStore {
public:
    HardwareStore() {}
    ~HardwareStore() {}

    void ADD(string item_name, int quantity, double price) {
        if (quantity <= 0) {
            cout << "Error: Quantity must be positive." << endl;
            return;
        }
        if (price < 0) {
            cout << "Error: Price must be non-negative." << endl;
            return;
        }
        inventory.push_back({item_name, quantity, price});
        numItems++;
    }

    void REMOVE(string item_name) {
        bool found = false;
        for (auto& item : inventory) {
            if (item.name == item_name) {
                inventory.erase(find(inventory.begin(), inventory.end(), item));
                numItems--;
                found = true;
                break;
            }
        }
        if (!found) {
            cout << "Error: Item not found." << endl;
        }
    }

    void UPDATE(string item_name, int new_quantity, double new_price) {
        bool found = false;
        for (auto& item : inventory) {
            if (item.name == item_name) {
                item.quantity = new_quantity;
                item.price = new_price;
                found = true;
                break;
            }
        }
        if (!found) {
            cout << "Error: Item not found." << endl;
        }
    }

    void DISPLAY() {
        if (numItems == 0) {
            cout << "No items in inventory." << endl;
            return;
        }
        for (const auto& item : inventory) {
            cout << "Item: " << item.name << ", Quantity: " << item.quantity << ", Price: $" << item.price << endl;
        }
    }

private:
    struct Item {
        string name;
        int quantity;
        double price;
    };

    vector<Item> inventory;
    int numItems = 0;
};

