import datetime

def add_project(project_name):
    if project_name not in project_times:
        project_times[project_name] = []
    return True

def start_time(project_name, time_str):
    try:
        hours, minutes = map(int, time_str.split(':'))
        time = datetime.datetime.strptime(f"{hours}:{minutes}", "%H:%M")
        project_times[project_name].append(time)
        return True
    except ValueError:
        return False

def stop_time(project_name, time_str):
    try:
        hours, minutes = map(int, time_str.split(':'))
        time = datetime.datetime.strptime(f"{hours}:{minutes}", "%H:%M")
        if project_name in project_times:
            project_times[project_name].append(time)
            return True
        return False
    except ValueError:
        return False

def report(project_name):
    if project_name not in project_times:
        return False
    times = project_times[project_name]
    total_seconds = 0
    for t in times:
        total_seconds += (t - times[0]).total_seconds()
    hours = total_seconds // 3600
    minutes = (total_seconds % 3600) // 60
    return f"{hours} hours and {minutes} minutes"

def main():
    project_times = {}
    while True:
        command = input("Enter command: ").strip().split()
        if command[0] == "ADD_PROJECT":
            if len(command) < 2:
                print("Invalid command")
                continue
            project_name = command[1]
            if add_project(project_name):
                print(f"Project '{project_name}' added")
            else:
                print("Project already exists")
        elif command[0] == "START_TIME":
            if len(command) < 3:
                print("Invalid command")
                continue
            project_name = command[1]
            time_str = command[2]
            if start_time(project_name, time_str):
                print(f"Started time for '{project_name}' at {time_str}")
            else:
                print("Invalid time format")
        elif command[0] == "STOP_TIME":
            if len(command) < 3:
                print("Invalid command")
                continue
            project_name = command[1]
            time_str = command[2]
            if stop_time(project_name, time_str):
                print(f"Stopped time for '{project_name}' at {time_str}")
            else:
                print("Invalid time format")
        elif command[0] == "REPORT":
            if len(command) < 2:
                print("Invalid command")
                continue
            project_name = command[1]
            result = report(project_name)
            if result:
                print(result)
            else:
                print("Project does not exist")
        else:
            print("Unknown command")

if __name__ == "__main__":
    main()
