function manageTemperatureRecords() {
    this.records = [];

    this.addRecord = function(location, temperature) {
        if (!location || !temperature) {
            throw new Error("Location and temperature are required.");
        }
        if (!this.records.length) {
            throw new Error("No records available.");
        }
        const existingRecord = this.records.find(record => record.location === location);
        if (existingRecord) {
            existingRecord.temperature = temperature;
        } else {
            this.records.push({ location, temperature });
        }
    };

    this.getAverage = function(location) {
        if (!location) {
            throw new Error("Location is required.");
        }
        if (!this.records.length) {
            throw new Error("No records available.");
        }
        const locationRecords = this.records.filter(record => record.location === location);
        if (!locationRecords.length) {
            throw new Error("Location does not exist.");
        }
        const average = locationRecords.reduce((sum, record) => sum + record.temperature, 0) / locationRecords.length;
        return average;
    };

    this.removeRecord = function(location, date) {
        if (!location || !date) {
            throw new Error("Location and date are required.");
        }
        if (!this.records.length) {
            throw new Error("No records available.");
        }
        const locationRecords = this.records.filter(record => record.location === location);
        if (!locationRecords.length) {
            throw new Error("Location does not exist.");
        }
        const recordToRemove = locationRecords.find(record => record.date === date);
        if (!recordToRemove) {
            throw new Error("Record not found.");
        }
        this.records = this.records.filter(record => record.location !== location || record.date !== date);
    };

    this.updateRecord = function(location, date, newTemperature) {
        if (!location || !date || !newTemperature) {
            throw new Error("Location, date, and new temperature are required.");
        }
        if (!this.records.length) {
            throw new Error("No records available.");
        }
        const locationRecords = this.records.filter(record => record.location === location);
        if (!locationRecords.length) {
            throw new Error("Location does not exist.");
        }
        const recordToUpdate = locationRecords.find(record => record.date === date);
        if (!recordToUpdate) {
            throw new Error("Record not found.");
        }
        recordToUpdate.temperature = newTemperature;
    };
}
