pub struct FileManager {
    files: std::collections::HashMap<String, String>,
}

impl FileManager {
    pub fn new() -> Self {
        FileManager {
            files: std::collections::HashMap::new(),
        }
    }

    pub fn create_file(&mut self, path: String, content: String) -> Result<(), String> {
        self.files.insert(path, content);
        Ok(())
    }

    pub fn read_file(&self, path: String) -> Result<String, String> {
        match self.files.get(&path) {
            Some(content) => Ok(content.clone()),
            None => Err("File not found".to_string()),
        }
    }

    pub fn update_file(&mut self, path: String, new_content: String) -> Result<(), String> {
        if let Some(content) = self.files.get_mut(&path) {
            *content = new_content;
            Ok(())
        } else {
            Err("File not found".to_string())
        }
    }

    pub fn delete_file(&mut self, path: String) -> Result<(), String> {
        self.files.remove(&path);
        Ok(())
    }
}
