#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Structure for a process
typedef struct process {
    char name[50];
    int priority;
    struct process* next;
} Process;

// Function to create a new process
Process* create_process(char* name, int priority) {
    Process* new_process = (Process*)malloc(sizeof(Process));
    if (!new_process) return NULL;
    strcpy(new_process->name, name);
    new_process->priority = priority;
    new_process->next = NULL;
    return new_process;
}

// Function to add a process
void add_process(Process** head, char* name, int priority) {
    Process* new_process = create_process(name, priority);
    if (!new_process) return;
    new_process->next = *head;
    *head = new_process;
}

// Function to kill a process by name
void kill_process(Process** head, char* name) {
    Process* current = *head;
    Process* prev = NULL;
    while (current) {
        if (strcmp(current->name, name) == 0) {
            if (prev) {
                prev->next = current->next;
            } else {
                *head = current->next;
            }
            free(current);
            return;
        }
        prev = current;
        current = current->next;
    }
}

// Function to kill processes by priority
void kill_processes_by_priority(Process** head, int priority) {
    Process* current = *head;
    Process* prev = NULL;
    while (current) {
        if (current->priority == priority) {
            if (prev) {
                prev->next = current->next;
            } else {
                *head = current->next;
            }
            free(current);
        }
        prev = current;
        current = current->next;
    }
}

// Function to list processes sorted by priority
void list_processes(Process* head) {
    Process* current = head;
    while (current) {
        printf("Name: %s, Priority: %d\n", current->name, current->priority);
        current = current->next;
    }
}

int main() {
    Process* head = NULL;
    char command[100];
    char name[50];
    int priority;
    int choice;

    while (1) {
        printf("Enter command (ADD, KILL, KILL_PRIORITY, LIST): ");
        scanf("%s", command);

        if (strcmp(command, "ADD") == 0) {
            printf("Enter process name: ");
            scanf("%s", name);
            printf("Enter priority: ");
            scanf("%d", &priority);
            add_process(&head, name, priority);
        } else if (strcmp(command, "KILL") == 0) {
            printf("Enter process name to kill: ");
            scanf("%s", name);
            kill_process(&head, name);
        } else if (strcmp(command, "KILL_PRIORITY") == 0) {
            printf("Enter priority to kill: ");
            scanf("%d", &priority);
            kill_processes_by_priority(&head, priority);
        } else if (strcmp(command, "LIST") == 0) {
            list_processes(head);
        } else {
            printf("Unknown command\n");
        }
    }

    return 0;
}

