function manageTodos(commands) {
    const todos = [];
    const taskIds = [];

    function addTask(description) {
        const taskId = Date.now();
        const newTask = { taskId, description, completed: false };
        todos.push(newTask);
        taskIds.push(taskId);
        return `Task ${taskId} added.`;
    }

    function completeTask(taskId) {
        const index = taskIds.indexOf(taskId);
        if (index === -1) {
            return 'Task not found.';
        }
        todos[index].completed = true;
        return `Task ${taskId} marked as completed.`;
    }

    function deleteTask(taskId) {
        const index = taskIds.indexOf(taskId);
        if (index === -1) {
            return 'Task not found.';
        }
        taskIds.splice(index, 1);
        todos.splice(index, 1);
        return `Task ${taskId} deleted.`;
    }

    function listTasks() {
        return todos.map(task => ({
            taskId: task.taskId,
            description: task.description,
            completed: task.completed
        }));
    }

    switch (commands[0]) {
        case 'add':
            if (commands.length < 2) {
                return 'Invalid command.';
            }
            const description = commands[1];
            return addTask(description);
        case 'complete':
            if (commands.length < 2) {
                return 'Invalid command.';
            }
            const taskId = parseInt(commands[1]);
            return completeTask(taskId);
        case 'delete':
            if (commands.length < 2) {
                return 'Invalid command.';
            }
            const taskIdToDelete = parseInt(commands[1]);
            return deleteTask(taskIdToDelete);
        case 'list':
            return listTasks();
        default:
            return 'Invalid command.';
    }
}
