#define MAX_SETTINGS 10

typedef struct {
    char name[20];
    char value[20];
} Setting;

Setting settings[MAX_SETTINGS];
int num_settings = 0;

void initSettings() {
    for (int i = 0; i < MAX_SETTINGS; i++) {
        settings[i].name[0] = '\0';
        settings[i].value[0] = '\0';
    }
}

void addSetting(const char *name, const char *value) {
    if (num_settings >= MAX_SETTINGS) {
        return;
    }
    strcpy(settings[num_settings].name, name);
    strcpy(settings[num_settings].value, value);
    num_settings++;
}

void removeSetting(const char *name) {
    for (int i = 0; i < num_settings; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            for (int j = i; j < num_settings - 1; j++) {
                settings[j] = settings[j + 1];
            }
            num_settings--;
            break;
        }
    }
}

void printSettings() {
    for (int i = 0; i < num_settings; i++) {
        printf("Setting: %s - Value: %s\n", settings[i].name, settings[i].value);
    }
}

void setSetting(const char *name, const char *value) {
    for (int i = 0; i < num_settings; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            strcpy(settings[i].value, value);
            return;
        }
    }
    printf("Error: Setting '%s' not found.\n", name);
}

void getSetting(const char *name) {
    for (int i = 0; i < num_settings; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            printf("Setting '%s' value: %s\n", name, settings[i].value);
            return;
        }
    }
    printf("Error: Setting '%s' not found.\n", name);
}

void resetSetting(const char *name) {
    for (int i = 0; i < num_settings; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            strcpy(settings[i].value, settings[i].value); // Reset to default
            return;
        }
    }
    printf("Error: Setting '%s' not found.\n", name);
}

void listAllSettings() {
    printf("List of settings:\n");
    printSettings();
}

void handleCommand(const char *command) {
    char *token = strtok(command, " ");
    if (token == NULL) {
        printf("Error: Invalid command.\n");
        return;
    }

    if (strcmp(token, "SET") == 0) {
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting name.\n");
            return;
        }
        token = strtok(NULL, " ");
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting value.\n");
            return;
        }
        setSetting(token, token);
    } else if (strcmp(token, "GET") == 0) {
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting name.\n");
            return;
        }
        token = strtok(NULL, " ");
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting name.\n");
            return;
        }
        getSetting(token);
    } else if (strcmp(token, "RESET") == 0) {
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting name.\n");
            return;
        }
        token = strtok(NULL, " ");
        if (token == NULL || token[0] == '\0') {
            printf("Error: Missing setting name.\n");
            return;
        }
        resetSetting(token);
    } else if (strcmp(token, "LIST_ALL") == 0) {
        listAllSettings();
    } else {
        printf("Error: Unknown command.\n");
    }
}

int main() {
    initSettings();
    char command[100];
    while (1) {
        printf("Enter command: ");
        fgets(command, sizeof(command), stdin);
        handleCommand(command);
    }
