#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <unistd.h>

// Mutex for thread safety
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

// Structure to represent a task
typedef struct {
    char name[20];
    int duration;
    int status; // 0: waiting, 1: running, 2: completed
    pthread_t thread;
} Task;

// Global array to hold tasks
Task tasks[100];
int task_count = 0;

// Function to check task status
void check_task(char *task_name) {
    pthread_mutex_lock(&mutex);
    for (int i = 0; i < task_count; i++) {
        if (strcmp(tasks[i].name, task_name) == 0) {
            printf("Status of task %s: ", task_name);
            if (tasks[i].status == 0) {
                printf("Waiting\n");
            } else if (tasks[i].status == 1) {
                printf("Running\n");
            } else {
                printf("Completed\n");
            }
            break;
        }
    }
    pthread_mutex_unlock(&mutex);
}

// Function to start a task
void start_task(char *task_name) {
    pthread_mutex_lock(&mutex);
    for (int i = 0; i < task_count; i++) {
        if (strcmp(tasks[i].name, task_name) == 0) {
            if (tasks[i].status == 0) {
                tasks[i].status = 1;
                pthread_create(&tasks[i].thread, NULL, (void *)start_task_func, tasks[i].name);
                printf("Task %s started\n", task_name);
                break;
            } else if (tasks[i].status == 1) {
                printf("Task %s is already running\n", task_name);
                pthread_mutex_unlock(&mutex);
                return;
            }
        }
    }
    printf("Task %s does not exist\n", task_name);
    pthread_mutex_unlock(&mutex);
}

// Function to start task (thread function)
void* start_task_func(void* arg) {
    Task* task = (Task*)arg;
    printf("Task %s is running\n", task->name);
    sleep(task->duration);
    task->status = 2;
    printf("Task %s completed\n", task->name);
    return NULL;
}

// Function to add a task
void add_task(char *task_name, int duration) {
    pthread_mutex_lock(&mutex);
    if (task_count >= 100) {
        printf("Maximum task count reached\n");
        pthread_mutex_unlock(&mutex);
        return;
    }
    tasks[task_count].name[0] = '\0';
    strcpy(tasks[task_count].name, task_name);
    tasks[task_count].duration = duration;
    tasks[task_count].status = 0;
    task_count++;
    pthread_mutex_unlock(&mutex);
}

// Function to cancel a task
void cancel_task(char *task_name) {
    pthread_mutex_lock(&mutex);
    for (int i = 0; i < task_count; i++) {
        if (strcmp(tasks[i].name, task_name) == 0) {
            if (tasks[i].status == 0 || tasks[i].status == 1) {
                tasks[i].status = 3; // Cancelled
                printf("Task %s cancelled\n", task_name);
                break;
            } else {
                printf("Task %s is already completed\n", task_name);
                pthread_mutex_unlock(&mutex);
                return;
            }
        }
    }
    printf("Task %s does not exist\n", task_name);
    pthread_mutex_unlock(&mutex);
}

// Command line parser
void execute_command(char *command) {
    char *tokens[4];
    char *token = strtok(command, " ");
    int i = 0;
    while (token != NULL) {
        tokens[i++] = token;
        token = strtok(NULL, " ");
    }

    if (i < 2) {
        printf("Invalid command\n");
        return;
    }

    if (strcmp(tokens[0], "ADD_TASK") == 0) {
        if (i != 3) {
            printf("Invalid number of arguments for ADD_TASK\n");
            return;
        }
        add_task(tokens[1], atoi(tokens[2]));
    } else if (strcmp(tokens[0], "START_TASK") == 0) {
        if (i != 2) {
            printf("Invalid number of arguments for START_TASK\n");
            return;
        }
        start_task(tokens[1]);
    } else if (strcmp(tokens[0], "CHECK_TASK") == 0) {
        if (i != 2) {
            printf("Invalid number of arguments for CHECK_TASK\n");
            return;
        }
        check_task(tokens[1]);
    } else if (strcmp(tokens[0], "CANCEL_TASK") == 0) {
        if (i != 2) {
            printf("Invalid number of arguments for CANCEL_TASK\n");
            return;
        }
        cancel_task(tokens[1]);
    } else {
        printf("Unknown command\n");
    }
}

int main() {
    char command[256];
    while (1) {
        printf("Enter command: ");
        fgets(command, sizeof(command), stdin);
        execute_command(command);
    }
    return 0;
}

