class FileManager {
public:
    FileManager() : fileStream(nullptr) {}
    ~FileManager() { closeFile(); }

    void openFile(string fileName) {
        fileStream = new std::ifstream(fileName);
        if (!fileStream->good()) {
            throw std::runtime_error("Failed to open file: " + fileName);
        }
    }

    void writeFile(string data) {
        if (!fileStream) {
            throw std::runtime_error("File is not open");
        }
        fileStream->write(data.c_str(), data.size());
        if (fileStream->fail()) {
            throw std::runtime_error("Failed to write to file");
        }
    }

    string readFile() {
        if (!fileStream) {
            throw std::runtime_error("File is not open");
        }
        std::string content;
        fileStream->getline(content);
        return content;
    }

    void closeFile() {
        if (fileStream) {
            fileStream->close();
            fileStream = nullptr;
        }
    }

private:
    std::ifstream* fileStream;
};

