        let mut input = String::new();
        io::stdin()
            .read_line(&mut input)
            .expect("Failed to read input");

        let operation: &str = input.trim();
        if operation == "exit" {
            break;
        }

        let mut tokens: Vec<&str> = operation.split_whitespace().collect();
        if tokens.len() < 3 {
            println!("Invalid input. Please provide two numbers and an operation.");
            continue;
        }

        let op = tokens[0];
        let num1 = tokens[1].parse::<i32>().expect("Invalid number");
        let num2 = tokens[2].parse::<i32>().expect("Invalid number");

        match op {
            "ADD" => {
                let result = num1 + num2;
                println!("Result: {}", result);
            }
            "SUBTRACT" => {
                let result = num1 - num2;
                println!("Result: {}", result);
