 * @param {string} productId - product identifier
 * @param {number} quantity - quantity to add or update
 * @returns {string} - message indicating success or error
 */
function manageShoppingCart(productId, quantity) {
    // Initialize cart as an object to store products
    let cart = {};

    /**
     * Adds a product with a specified quantity to the shopping cart
     * @param {string} productId - product identifier
     * @param {number} quantity - quantity to add
     * @returns {string} - message indicating success
     */
    function addProduct(productId, quantity) {
        if (!productId || typeof productId !== 'string') {
            return "Error: Product ID must be a string.";
        }
        if (quantity <= 0) {
            return "Error: Quantity must be a positive number.";
        }
        if (cart[productId]) {
            cart[productId] += quantity;
        } else {
            cart[productId] = quantity;
        }
        return "Product added to cart successfully.";
    }

    /**
     * Removes a product identified by its productId from the shopping cart
     * @param {string} productId - product identifier
     * @returns {string} - message indicating success or error
     */
    function removeProduct(productId) {
        if (!productId || typeof productId !== 'string') {
            return "Error: Product ID must be a string.";
        }
        if (!cart[productId]) {
            return "Error: Product not found in cart.";
        }
        delete cart[productId];
        return "Product removed from cart successfully.";
    }

    /**
     * Updates the quantity of a specific product in the shopping cart
     * @param {string} productId - product identifier
     * @param {number} quantity - new quantity
     * @returns {string} - message indicating success or error
     */
    function updateProduct(productId, quantity) {
        if (!productId || typeof productId !== 'string') {
            return "Error: Product ID must be a string.";
        }
        if (quantity <= 0) {
            return "Error: Quantity must be a positive number.";
        }
        if (!cart[productId]) {
            return "Error: Product not found in cart.";
        }
        cart[productId] = quantity;
        return "Product quantity updated successfully.";
    }

    /**
     * Retrieves the quantity of a product in the shopping cart
     * @param {string} productId - product identifier
     * @returns {string} - message indicating success or error
     */
    function getProduct(productId) {
        if (!productId || typeof productId !== 'string') {
            return "Error: Product ID must be a string.";
        }
        if (!cart[productId]) {
            return "Error: Product not found in cart.";
        }
        return `Quantity of product ${productId} is ${cart[productId]}.`;
    }

    // Return the appropriate result based on the command
    if (productId && quantity) {
        return addProduct(productId, quantity);
    } else if (productId) {
        return getProduct(productId);
    } else if (productId && quantity <= 0) {
        return "Error: Quantity must be a positive number.";
    } else if (productId && !cart[productId]) {
        return "Error: Product not found in cart.";
    } else if (quantity <= 0) {
        return "Error: Quantity must be a positive number.";
    } else {
        return "Error: Invalid command or parameters.";
    }
}
