#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <sys/socket.h>
#include <netinet/in.h>

// Server class
class Server {
public:
    Server(int port) : server_socket(-1), port(port) {
        server_socket = socket(AF_INET, SOCK_STREAM, 0);
        if (server_socket < 0) {
            perror("Socket creation failed");
            exit(EXIT_FAILURE);
        }

        struct sockaddr_in server_addr;
        server_addr.sin_family = AF_INET;
        server_addr.sin_port = htons(port);
        server_addr.sin_addr.s_addr = INADDR_ANY;

        if (bind(server_socket, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
            perror("Bind failed");
            exit(EXIT_FAILURE);
        }

        if (listen(server_socket, 5) < 0) {
            perror("Listen failed");
            exit(EXIT_FAILURE);
        }
    }

    ~Server() {
        if (server_socket >= 0) {
            close(server_socket);
        }
    }

    void start() {
        printf("Server is running on port %d\n", port);

        struct sockaddr_in client_addr;
        int client_len = sizeof(client_addr);

        while (1) {
            printf("Waiting for client connection...\n");
            int client_socket = accept(server_socket, (struct sockaddr*)&client_addr, &client_len);
            if (client_socket < 0) {
                perror("Accept failed");
                continue;
            }

            char request[1024];
            recv(client_socket, request, sizeof(request), 0);
            printf("Received: %s\n", request);

            // Parse request
            char* cmd = strtok(request, " ");
            if (cmd == NULL) {
                send(client_socket, "Invalid command", sizeof("Invalid command"), 0);
                continue;
            }

            if (strcmp(cmd, "CPU_USAGE") == 0) {
                char response[1024];
                sprintf(response, "CPU_USAGE: 75%");
                send(client_socket, response, sizeof(response), 0);
            } else if (strcmp(cmd, "MEMORY_USAGE") == 0) {
                char response[1024];
                sprintf(response, "MEMORY_USAGE: 60%");
                send(client_socket, response, sizeof(response), 0);
            } else if (strcmp(cmd, "DISK_USAGE") == 0) {
                char response[1024];
                sprintf(response, "DISK_USAGE: 40%");
                send(client_socket, response, sizeof(response), 0);
            } else {
                send(client_socket, "Invalid command", sizeof("Invalid command"), 0);
            }

            close(client_socket);
        }
    }

private:
    int server_socket;
    int port;
};

// Client class
class Client {
public:
    Client(int server_port) : server_socket(-1), server_port(server_port) {
        server_socket = socket(AF_INET, SOCK_STREAM, 0);
        if (server_socket < 0) {
            perror("Socket creation failed");
            exit(EXIT_FAILURE);
        }

        struct sockaddr_in server_addr;
        server_addr.sin_family = AF_INET;
        server_addr.sin_port = htons(server_port);
        server_addr.sin_addr.s_addr = INADDR_ANY;

        if (connect(server_socket, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
            perror("Connection failed");
            exit(EXIT_FAILURE);
        }
    }

    ~Client() {
        if (server_socket >= 0) {
            close(server_socket);
        }
    }

    void sendRequest(const char* cmd) {
        char request[1024];
        sprintf(request, "%s", cmd);
        send(server_socket, request, sizeof(request), 0);
    }

    void receiveResponse(char* buffer) {
        int bytes_received = recv(server_socket, buffer, sizeof(buffer), 0);
        if (bytes_received > 0) {
            buffer[bytes_received] = '\0';
            printf("Received: %s\n", buffer);
        }
    }

private:
    int server_socket;
    int server_port;
};

// Main function
int main() {
    Server server(8080);
    Client client(8080);

    server.start();
    client.sendRequest("CPU_USAGE");
    client.sendRequest("MEMORY_USAGE");
    client.sendRequest("DISK_USAGE");

    return 0;
}
