use std::time::SystemTime;

fn start_session(user_id: String) -> Option<u32> {
    // Store the start time for the user
    let start_time = SystemTime::now().duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs();
    // Store the start time in a struct or variable
    // For simplicity, we'll use a static variable here
    static SESSION_START: std::sync::Mutex<Option<u32>> = std::sync::Mutex::new(None);
    SESSION_START.lock().unwrap().replace(start_time);
    Some(start_time)
}

fn check_session(user_id: String, session_duration: u32) -> bool {
    // Retrieve the start time for the user
    let start_time = unsafe { SESSION_START.lock().unwrap().take() };
    if let Some(start_time) = start_time {
        let current_time = SystemTime::now().duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs();
        let elapsed = current_time - start_time;
        elapsed <= session_duration as u32
    } else {
        false
    }
}

fn end_session(user_id: String) {
    // Retrieve the start time for the user
    let start_time = unsafe { SESSION_START.lock().unwrap().take() };
    if let Some(start_time) = start_time {
        // Clear the start time for the user
        SESSION_START.lock().unwrap().replace(None);
    }
}
