class ExpenseTracker:
    def __init__(self):
        self.expenses: Dict[str, float] = {}

    def add_expense(self, name: str, amount: float) -> None:
        if name in self.expenses:
            self.expenses[name] += amount
        else:
            self.expenses[name] = amount
        if len(self.expenses) > MAX_EXPENSES:
            # Remove the oldest expense to maintain limit
            self.expenses.popitem()

    def remove_expense(self, name: str) -> None:
        if name in self.expenses:
            del self.expenses[name]
        else:
            raise ValueError(f"Expense '{name}' not found.")

    def get_expense(self, name: str) -> Optional[float]:
        return self.expenses.get(name, None)

    def total_expenses(self) -> float:
        return sum(self.expenses.values())
