function computeStats(data) {
    let max = -Infinity;
    let min = Infinity;
    let sum = 0;

    for (let score of data) {
        sum += score;
        if (score > max) {
            max = score;
        }
        if (score < min) {
            min = score;
        }
    }

    let average = sum / data.length;

    return { max, min, average };
}
