class MusicPlaylist {
private:
    std::vector<std::string> songs;
    std::mutex mtx;

public:
    void addSong(const std::string& song_name) {
        std::lock_guard<std::mutex> lock(mtx);
        songs.push_back(song_name);
    }

    void removeSong(const std::string& song_name) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find(songs.begin(), songs.end(), song_name);
        if (it != songs.end()) {
            songs.erase(it);
        } else {
            std::cerr << "Song not found in playlist." << std::endl;
        }
    }

    void play() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!songs.empty()) {
            std::cout << "Playing: " << songs.back() << std::endl;
            songs.pop_back();
        } else {
            std::cerr << "No songs in playlist." << std::endl;
        }
    }

    void listSongs() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!songs.empty()) {
            std::cout << "Songs in playlist:" << std::endl;
            for (const auto& song : songs) {
                std::cout << " - " << song << std::endl;
            }
        } else {
            std::cerr << "No songs in playlist." << std::endl;
        }
    }
};

int main() {
    MusicPlaylist playlist;
    std::string command;

    while (std::cin >> command) {
        if (command == "ADD") {
            std::string song_name;
            std::cin >> song_name;
            playlist.addSong(song_name);
        } else if (command == "REMOVE") {
            std::string song_name;
            std::cin >> song_name;
            playlist.removeSong(song_name);
        } else if (command == "PLAY") {
            playlist.play();
        } else if (command == "LIST") {
            playlist.listSongs();
        } else {
            std::cerr << "Unknown command." << std::endl;
        }
    }

    return 0;
}

