#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define OP_ADD 1
#define OP_SUBTRACT 2
#define OP_MULTIPLY 3
#define OP_DIVIDE 4
#define ERROR_DIVISION_BY_ZERO "Division by zero error"

int main() {
    char input[100];
    char op[5];
    int x, y;
    int opCode;

    while (1) {
        printf("Enter command (ADD, SUBTRACT, MULTIPLY, DIVIDE, or Q to quit): ");
        fgets(input, sizeof(input), stdin);

        // Check for exit command
        if (strncmp(input, "Q", 1) == 0) {
            break;
        }

        // Parse command
        sscanf(input, "%s %d %d", op, &x, &y);

        // Check if command is valid
        if (strncmp(op, "ADD", 3) == 0) {
            opCode = OP_ADD;
        } else if (strncmp(op, "SUBTRACT", 7) == 0) {
            opCode = OP_SUBTRACT;
        } else if (strncmp(op, "MULTIPLY", 7) == 0) {
            opCode = OP_MULTIPLY;
        } else if (strncmp(op, "DIVIDE", 5) == 0) {
            opCode = OP_DIVIDE;
        } else {
            printf("Invalid command.\n");
            continue;
        }

        // Perform operation
        switch (opCode) {
            case OP_ADD:
                printf("%d + %d = %d\n", x, y, x + y);
                break;
            case OP_SUBTRACT:
                printf("%d - %d = %d\n", x, y, x - y);
                break;
            case OP_MULTIPLY:
                printf("%d * %d = %d\n", x, y, x * y);
                break;
            case OP_DIVIDE:
                if (y == 0) {
                    printf(ERROR_DIVISION_BY_ZERO "\n");
                } else {
                    printf("%d / %d = %d\n", x, y, x / y);
                }
                break;
            default:
                printf("Invalid operation.\n");
        }
    }

    return 0;
}

