use std::collections::HashMap;
use std::sync::{Mutex, Arc};
use std::thread;
use std::time::Duration;

struct User {
    username: String,
    connected: bool,
}

struct ChatServer {
    users: Mutex<HashMap<String, User>>,
    messages: Mutex<Vec<String>>,
    is_running: bool,
}

impl ChatServer {
    fn new() -> Self {
        ChatServer {
            users: Mutex::new(HashMap::new()),
            messages: Mutex::new(Vec::new()),
            is_running: false,
        }
    }

    fn start(&mut self) {
        self.is_running = true;
        thread::spawn(move || {
            loop {
                if !self.is_running {
                    break;
                }
                thread::sleep(Duration::from_millis(100));
                if self.is_running {
                    self.handle_messages();
                }
            }
        });
    }

    fn handle_messages(&self) {
        let messages = self.messages.lock().unwrap();
        for msg in messages.iter() {
            println!("Message: {}", msg);
        }
    }

    fn join_user(&self, username: &str) {
        let mut users = self.users.lock().unwrap();
        if users.contains_key(username) {
            return;
        }
        users.insert(username.to_string(), User {
            username: username.to_string(),
            connected: true,
        });
        self.send_notification(username, "Joined the chat");
    }

    fn leave_user(&self, username: &str) {
        let mut users = self.users.lock().unwrap();
        if let Some(user) = users.remove(username) {
            self.send_notification(username, "Left the chat");
        }
    }

    fn send_message(&self, username: &str, text: &str) {
        let mut messages = self.messages.lock().unwrap();
        messages.push(format!("{}: {}", username, text));
    }

    fn list_users(&self) -> Vec<String> {
        let users = self.users.lock().unwrap();
        users.keys().cloned().collect()
    }

    fn send_notification(&self, username: &str, message: &str) {
        let users = self.users.lock().unwrap();
        for (user, _) in users.iter() {
            if user == username {
                continue;
            }
            self.send_message(user, message);
        }
    }
}

fn main() {
    let server = Arc::new(ChatServer::new());
    let server = Arc::clone(&server);
    thread::spawn(move || {
        server.start();
    });

    // Simulate client connections
    let client1 = Arc::new(ChatServer::new());
    let client2 = Arc::new(ChatServer::new());

    thread::spawn(move || {
        client1.join_user("user1");
        client1.send_message("user1", "Hello, user2!");
        client1.leave_user("user1");
    });

    thread::spawn(move || {
        client2.join_user("user2");
        client2.send_message("user2", "Hello, user1!");
        client2.leave_user("user2");
    });
}
