#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_CUSTOMERS 100

typedef struct {
    int customerId;
    double balance;
} Account;

Account accounts[MAX_CUSTOMERS];
int accountCount = 0;

// Function to create a new account
void createAccount(int customerId, double initialBalance) {
    if (accountCount >= MAX_CUSTOMERS) {
        printf("Error: Maximum number of accounts reached.\n");
        return;
    }

    Account newAccount = {customerId, initialBalance};
    accounts[accountCount++] = newAccount;
    printf("Account created for customer %d with initial balance %.2f\n", customerId, initialBalance);
}

// Function to deposit money into an account
void deposit(int customerId, double amount) {
    int index = -1;
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            index = i;
            break;
        }
    }

    if (index == -1) {
        printf("Error: Customer ID not found.\n");
        return;
    }

    if (amount <= 0) {
        printf("Error: Deposit amount must be positive.\n");
        return;
    }

    accounts[index].balance += amount;
    printf("Deposited %.2f into account of customer %d.\n", amount, customerId);
}

// Function to withdraw money from an account
void withdraw(int customerId, double amount) {
    int index = -1;
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            index = i;
            break;
        }
    }

    if (index == -1) {
        printf("Error: Customer ID not found.\n");
        return;
    }

    if (amount <= 0) {
        printf("Error: Withdrawal amount must be positive.\n");
        return;
    }

    if (accounts[index].balance < amount) {
        printf("Error: Insufficient balance for withdrawal.\n");
        return;
    }

    accounts[index].balance -= amount;
    printf("Withdrew %.2f from account of customer %d.\n", amount, customerId);
}

// Function to get the current balance of an account
double getBalance(int customerId) {
    int index = -1;
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            index = i;
            break;
        }
    }

    if (index == -1) {
        printf("Error: Customer ID not found.\n");
        return 0.0;
    }

    return accounts[index].balance;
}

// Function to close an account
void closeAccount(int customerId) {
    int index = -1;
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            index = i;
            break;
        }
    }

    if (index == -1) {
        printf("Error: Customer ID not found.\n");
        return;
    }

    accounts[index].customerId = -1; // Mark as closed
    printf("Account for customer %d closed.\n", customerId);
}

int main() {
    // Example usage
    createAccount(101, 1000.0);
    deposit(101, 500.0);
    withdraw(101, 200.0);
    printf("Balance of customer 101: %.2f\n", getBalance(101));
    closeAccount(101);

    return 0;
}
