#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_TASKS 100

typedef struct task {
    int task_id;
    int priority;
    char name[50];
    struct task* next;
} Task;

typedef struct scheduler {
    Task* tasks;
    int size;
} Scheduler;

Scheduler* create_scheduler() {
    Scheduler* scheduler = (Scheduler*)malloc(sizeof(Scheduler));
    scheduler->tasks = NULL;
    scheduler->size = 0;
    return scheduler;
}

void destroy_scheduler(Scheduler* scheduler) {
    Task* current = scheduler->tasks;
    while (current) {
        Task* next = current->next;
        free(current);
        current = next;
    }
    free(scheduler);
}

void add_task(Scheduler* scheduler, int task_id, int priority, const char* name) {
    Task* new_task = (Task*)malloc(sizeof(Task));
    if (!new_task) {
        fprintf(stderr, "Memory allocation failed.\n");
        return;
    }
    new_task->task_id = task_id;
    new_task->priority = priority;
    strcpy(new_task->name, name);
    new_task->next = NULL;

    if (scheduler->size == 0) {
        scheduler->tasks = new_task;
    } else {
        Task* last = scheduler->tasks;
        while (last->next) {
            last = last->next;
        }
        last->next = new_task;
    }
    scheduler->size++;
}

void remove_task(Scheduler* scheduler, int task_id) {
    if (scheduler->size == 0) {
        fprintf(stderr, "Scheduler is empty.\n");
        return;
    }

    Task* current = scheduler->tasks;
    Task* previous = NULL;

    while (current) {
        if (current->task_id == task_id) {
            if (previous) {
                previous->next = current->next;
            } else {
                scheduler->tasks = current->next;
            }
            free(current);
            scheduler->size--;
            break;
        }
        previous = current;
        current = current->next;
    }
}

void change_priority(Scheduler* scheduler, int task_id, int new_priority) {
    if (scheduler->size == 0) {
        fprintf(stderr, "Scheduler is empty.\n");
        return;
    }

    Task* current = scheduler->tasks;
    Task* prev = NULL;

    while (current) {
        if (current->task_id == task_id) {
            current->priority = new_priority;
            break;
        }
        prev = current;
        current = current->next;
    }
}

Task* fetch_next_task(Scheduler* scheduler) {
    if (scheduler->size == 0) {
        return NULL;
    }

    Task* next_task = scheduler->tasks;
    scheduler->tasks = next_task->next;
    return next_task;
}

int main() {
    Scheduler* scheduler = create_scheduler();
    int choice;
    int task_id;
    char name[50];

    while (1) {
        printf("1. ADD_TASK\n2. REMOVE_TASK\n3. CHANGE_PRIORITY\n4. FETCH_NEXT_TASK\n5. EXIT\n");
        scanf("%d", &choice);

        switch (choice) {
            case 1:
                printf("Enter task ID: ");
                scanf("%d", &task_id);
                printf("Enter priority: ");
                scanf("%d", &task_id);
