const secondsPerMinute = 60;
const minutesPerHour = 60;
const hoursPerDay = 24;
const daysPerMonth = 30;
const monthsPerYear = 12;

function calculateTimeSpan(startTimeStamp, endTimeStamp) {
    // Validate timestamps
    if (typeof startTimeStamp !== 'number' || typeof endTimeStamp !== 'number') {
        throw new Error('Both timestamps must be numbers.');
    }
    if (startTimeStamp > endTimeStamp) {
        throw new Error('endTimeStamp must not be earlier than startTimeStamp.');
    }

    // Calculate time span
    const years = Math.floor((endTimeStamp - startTimeStamp) / (31557600000)); // 31557600000 = 31557600 * 1000 * 1000
    const remainingSeconds = endTimeStamp - startTimeStamp;
    const secondsPerYear = 31557600000;
    const yearsRemaining = Math.floor(remainingSeconds / secondsPerYear);
    const remainingSecondsAfterYears = remainingSeconds % secondsPerYear;

    const months = Math.floor(remainingSecondsAfterYears / (2628000)); // 2628000 = 60 * 60 * 24 * 30
    const remainingSecondsAfterMonths = remainingSecondsAfterYears % 2628000;

    const days = Math.floor(remainingSecondsAfterMonths / (86400)); // 86400 = 60 * 60 * 24
    const remainingSecondsAfterDays = remainingSecondsAfterMonths % 86400;

    const hours = Math.floor(remainingSecondsAfterDays / 3600);
    const remainingSecondsAfterHours = remainingSecondsAfterDays % 3600;

    const minutes = Math.floor(remainingSecondsAfterHours / 60);
    const remainingSecondsAfterMinutes = remainingSecondsAfterHours % 60;

    const seconds = remainingSecondsAfterMinutes;

    return {
        years: years,
        months: months,
        days: days,
        hours: hours,
        minutes: minutes,
        seconds: seconds
    };
}
