using namespace std;

class Flight {
public:
    string flightID;
    string flightName;
    int totalFlights = 0;
    map<string, int> passengers; // passengerName -> number of passengers

    Flight(string id, string name) : flightID(id), flightName(name) {}

    void addPassenger(string name) {
        if (passengers.find(name) != passengers.end()) {
            passengers[name]++; // Update count
        } else {
            passengers[name] = 1; // Add new passenger
        }
    }

    void removePassenger(string name) {
        if (passengers.find(name) != passengers.end()) {
            passengers[name]--;
            if (passengers[name] == 0) {
                passengers.erase(name);
            }
        }
    }

    int getPassengerCount(string name) {
        return passengers.find(name) != passengers.end() ? passengers[name] : 0;
    }

    void displayPassengers() {
        cout << "Passengers on flight " << flightID << ":\n";
        for (const auto& pair : passengers) {
            cout << "  " << pair.first << " - " << pair.second << " passengers\n";
        }
    }
};

class FlightReservationSystem {
public:
    map<string, Flight> flights; // flightID -> Flight object

    void addFlight(string flightID, string flightName) {
        if (flights.find(flightID) != flights.end()) {
            throw runtime_error("Flight already exists.");
        }
        flights[flightID] = Flight(flightID, flightName);
    }

    void bookFlight(string flightID, string passengerName) {
        if (flights.find(flightID) == flights.end()) {
            throw runtime_error("Flight does not exist.");
        }
        flights[flightID].addPassenger(passengerName);
    }

    void cancelFlight(string flightID, string passengerName) {
        if (flights.find(flightID) == flights.end()) {
            throw runtime_error("Flight does not exist.");
        }
        if (flights[flightID].getPassengerCount(passengerName) == 0) {
            throw runtime_error("Passenger not found.");
        }
        flights[flightID].removePassenger(passengerName);
    }

    void displayFlightList() {
        cout << "Scheduled flights:\n";
        for (const auto& pair : flights) {
            cout << "  Flight ID: " << pair.first << ", Name: " << pair.second.flightName << ", Passengers: ";
            for (const auto& pair2 : pair.second.passengers) {
                cout << pair2.first << " (" << pair2.second << ") ";
            }
            cout << endl;
        }
    }

    void displayPassengerList(string flightID) {
        if (flights.find(flightID) == flights.end()) {
            throw runtime_error("Flight does not exist.");
        }
        flights[flightID].displayPassengers();
    }
};

int main() {
    FlightReservationSystem system;

    // Example usage
    system.addFlight("FL123", "Delta Flight");
    system.bookFlight("FL123", "Alice");
    system.bookFlight("FL123", "Bob");
    system.cancelFlight("FL123", "Alice");

    system.displayFlightList();
    system.displayPassengerList("FL123");

    return 0;
}

