public class ParkingGarage {
    private int totalSpaces = 100;
    private int[] parkingSpaces = new int[totalSpaces];
    private int currentOccupied = 0;

    public void parkVehicle(String licensePlate) {
        if (currentOccupied >= totalSpaces) {
            System.out.println("No spots available.");
            return;
        }
        parkingSpaces[currentOccupied] = 1;
        currentOccupied++;
        System.out.println("Vehicle " + licensePlate + " parked.");
    }

    public void departVehicle(String licensePlate) {
        for (int i = 0; i < currentOccupied; i++) {
            if (parkingSpaces[i] == 1 && licensePlate.equals(String.valueOf(i))) {
                parkingSpaces[i] = 0;
                currentOccupied--;
                System.out.println("Vehicle " + licensePlate + " departed.");
                return;
            }
        }
        System.out.println("Vehicle not found.");
    }

    public int countAvailableSpaces() {
        int available = 0;
        for (int space : parkingSpaces) {
            if (space == 0) available++;
        }
        return available;
    }
}
