from typing import List, Dict, Union
import math

def compute_volatility(price_data: List[float]) -> float:
    if not price_data:
        raise ValueError("Price data cannot be empty")

    n = len(price_data)
    if n < 2:
        raise ValueError("Price data must have at least two points")

    mean = sum(price_data) / n
    squared_diffs = [(x - mean) ** 2 for x in price_data]
    variance = sum(squared_diffs) / (n - 1)
    return math.sqrt(variance)

def evaluate_risk(profile: Dict[str, float], financial_products: List[Dict[str, Union[float, str]]]) -> str:
    if not profile:
        raise ValueError("Profile cannot be empty")

    if not financial_products:
        raise ValueError("Financial products cannot be empty")

    total_risk = 0.0

    for product in financial_products:
        if "risk" not in product:
            raise ValueError("Product must have a 'risk' key")
        total_risk += product["risk"] * profile.get(product["name"], 0)

    if total_risk == 0:
        return "No risk in the portfolio"

    risk_level = "Low" if total_risk < 0.5 else ("Moderate" if total_risk < 1.0 else "High")
    return risk_level
