#include <iostream>

// Define a node for the singly linked list
struct Node {
    int data;
    Node* next;
};

// Define the stack structure
class Stack {
private:
    Node* head;
    int size;

public:
    // Constructor
    Stack() : head(nullptr), size(0) {}

    // Push a new element to the stack
    void push(int value) {
        Node* new_node = new Node;
        new_node->data = value;
        new_node->next = head;
        head = new_node;
        size++;
    }

    // Pop an element from the stack
    int pop() {
        if (isEmpty()) {
            std::cerr << "Error: Stack is empty." << std::endl;
            return -1; // Invalid operation
        }
        int value = head->data;
        Node* temp = head;
        head = head->next;
        size--;
        delete temp;
        return value;
    }

    // Peek at the top element of the stack
    int peek() {
        if (isEmpty()) {
            std::cerr << "Error: Stack is empty." << std::endl;
            return -1; // Invalid operation
        }
        return head->data;
    }

    // Check if the stack is empty
    bool isEmpty() const {
        return head == nullptr;
    }

    // Get the size of the stack
    int size() const {
        return size;
    }
};
