function rateLimit(calls) {
    // Token bucket algorithm
    let tokens = 0;
    const now = Date.now();

    // Add tokens to the bucket
    if (now - lastTokenTime < interval) {
        tokens += Math.min(maxCallsPerMinute, Math.floor((now - lastTokenTime) / interval) * maxCallsPerMinute);
    }

    // If there are tokens, allow the request
    if (tokens > 0) {
