class Cache:
    def __init__(self, max_size):
        self.max_size = max_size
        self.cache = {}
        self.order = []

    def add_item(self, key, value):
        if self._is_item_exists(key):
            self._mark_as_used(key)
        if len(self.cache) >= self.max_size:
            self._remove_least_used_item()
        self.cache[key] = value
        self.order.append(key)

    def get_item(self, key):
        if self._is_item_exists(key):
            self._mark_as_used(key)
            return self.cache[key]
        else:
            raise KeyError(f"Item with key {key} not found in cache")

    def remove_item(self, key):
        if self._is_item_exists(key):
            del self.cache[key]
            self.order.remove(key)
        else:
            raise KeyError(f"Item with key {key} not found in cache")

    def clear_cache(self):
        self.cache.clear()
        self.order.clear()

    def _is_item_exists(self, key):
        return key in self.cache

    def _mark_as_used(self, key):
        self.order.remove(key)
        self.order.append(key)

    def _remove_least_used_item(self):
        if self.order:
            oldest = self.order.pop(0)
            del self.cache[oldest]
