#include <iostream>
#include <map>
#include <mutex>
#include <string>

using namespace std;

// Type declarations
typedef map<string, string> DB;

// Mutex for thread safety
mutex mtx;

// Database
DB db;

// Function to set a key-value pair
void SET(string key, string value) {
    mtx.lock();
    db[key] = value;
    mtx.unlock();
}

// Function to get a key's value
string GET(string key) {
    mtx.lock();
    if (db.find(key) != db.end()) {
        string value = db[key];
        mtx.unlock();
        return value;
    } else {
        mtx.unlock();
        return "Key not found";
    }
}

// Function to delete a key-value pair
void DELETE(string key) {
    mtx.lock();
    if (db.find(key) != db.end()) {
        db.erase(key);
    } else {
        mtx.unlock();
        cout << "Key not found" << endl;
    }
    mtx.unlock();
}

// Function to update a key's value
void UPDATE(string key, string value) {
    mtx.lock();
    if (db.find(key) != db.end()) {
        db[key] = value;
    } else {
        mtx.unlock();
        cout << "Key not found" << endl;
    }
    mtx.unlock();
}

int main() {
    // Example usage
    SET("name", "Alice");
    SET("age", "30");
    SET("city", "New York");

    cout << "GET name: " << GET("name") << endl;
    cout << "GET age: " << GET("age") << endl;
    cout << "GET city: " << GET("city") << endl;

    DELETE("name");
    cout << "GET name: " << GET("name") << endl;

    UPDATE("age", "31");
    cout << "GET age: " << GET("age") << endl;

    return 0;
}
